window.readingProgress={init:function(){this.initProgressBar(),this.initReadingPosition(),this.calculateReadingTime()},initProgressBar:function(){const t=document.querySelector(".reading-progress-bar");if(!t)return;const e=()=>{const e=window.innerHeight,n=document.documentElement.scrollHeight-e,s=window.scrollY,o=s/n*100;t.style.width=o+"%"};window.addEventListener("scroll",e),window.addEventListener("resize",e),e()},initReadingPosition:function(){const t=document.querySelector("article");if(!t)return;const n=t.id||window.location.pathname,e=localStorage.getItem(`reading-position-${n}`);setTimeout(()=>{if(e&&parseInt(e)>100){const t=confirm("偵測到您上次讀到這裡，要跳轉到上次的閱讀位置嗎？");t&&window.scrollTo({top:parseInt(e),behavior:"smooth"})}},500);let s;window.addEventListener("scroll",()=>{clearTimeout(s),s=setTimeout(()=>{const e=window.scrollY;localStorage.setItem(`reading-position-${n}`,e)},2e3)})},calculateReadingTime:function(){const e=document.querySelector("article");if(!e)return;const t=e.textContent||e.innerText,s=(t.match(/[\u4e00-\u9fa5]/g)||[]).length,o=(t.match(/[a-zA-Z]+/g)||[]).length,i=s+o,a=300,n=Math.ceil(i/a);this.updateReadingTimeDisplay(n),this.updateReadingTimeTitle(n)},updateReadingTimeDisplay:function(e){const t=document.querySelector(".estimate-text");if(!t)return;if(e<1)t.textContent="<1m";else if(e<60)t.textContent=`${e} min`;else{const n=Math.floor(e/60),s=e%60;s===0?t.textContent=`${n}h`:t.textContent=`${n}h${s}m`}},updateReadingTimeTitle:function(e){const t=document.querySelector(".reading-time-on-progress");if(!t)return;if(e<1)t.title="閱讀時間：少於 1 分鐘";else if(e<60)t.title=`閱讀時間：約 ${e} 分鐘`;else{const n=Math.floor(e/60),s=e%60;t.title=`閱讀時間：約 ${n} 小時 ${s} 分鐘`}}}